import React from 'react';
import { FaGithub, FaLinkedin, FaEnvelope } from 'react-icons/fa';

const Footer = () => {
  return (
    <footer id="footer" className="footer-section bg-dark text-white text-center py-4">
      <div className="container">
        <div className="social-links mb-3">
          <a href="https://github.com/yourusername" target="_blank" rel="noopener noreferrer" className="text-white me-3">
            <FaGithub size={24} />
          </a>
          <a href="https://linkedin.com/in/yourusername" target="_blank" rel="noopener noreferrer" className="text-white me-3">
            <FaLinkedin size={24} />
          </a>
          <a href="mailto:youremail@example.com" className="text-white">
            <FaEnvelope size={24} />
          </a>
        </div>
        <p>&copy; {new Date().getFullYear()} Your Name. All rights reserved.</p>
      </div>
    </footer>
  );
};

export default Footer;
